const newDocuments = toInt(row.new_documents);
const newFinancialTransactions = toInt(row.new_financial_transactions);
const dailyReconciliations = toInt(row.daily_reconciliations);

const httpTotal = toInt(logSummary.http_requests_total);
const http2xx = toInt(logSummary.http_2xx);
const http3xx = toInt(logSummary.http_3xx);
const http4xx = toInt(logSummary.http_4xx);
const http5xx = toInt(logSummary.http_5xx);
const topPaths = formatList(logSummary.top_paths, 'n/d');
const errorPaths = formatList(logSummary.error_paths, 'nenhuma');
const errorServices = formatMap(logSummary.errors_by_service, 'nenhum');
const warnServices = formatMap(logSummary.warns_by_service, 'nenhum');
const totalErrorSignals = Object.values(logSummary.errors_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const totalWarnSignals = Object.values(logSummary.warns_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const logSummaryError = logSummary._meta_error ? `- observacao: resumo de logs incompleto (${logSummary._meta_error})` : null;

const referenceLines = checkedDateKey && reportDateKey && checkedDateKey === reportDateKey
