const keywords = ['ai','machine learning','data','backend','api','python','llm','rag','architecture','microservices','cloud','agent','agents','openai','gemini','vector','database','postgres','redis','docker','kubernetes'];
const now = Date.now();
const maxCandidates = 15;
const byKey = new Map();

for (const item of items) {
  const title = String(item.json.title || '').trim();
  const snippet = String(item.json.contentSnippet || item.json.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const link = String(item.json.link || '').trim();
  const source = String(item.json.creator || item.json.source || item.json.feedTitle || item.json.isoDate || 'RSS').trim();
  const isoDate = String(item.json.isoDate || item.json.pubDate || '').trim();
  const text = `${title} ${snippet}`.toLowerCase();

  if (!title || !link) {
    continue;
  }

  const keywordHits = keywords.filter((keyword) => text.includes(keyword)).length;
  if (keywordHits === 0) {
    continue;
  }

  const publishedTs = isoDate ? Date.parse(isoDate) : NaN;
  let score = keywordHits * 2;
  if (Number.isFinite(publishedTs)) {
    const ageHours = (now - publishedTs) / (1000 * 60 * 60);
    if (ageHours <= 24) score += 4;
    else if (ageHours <= 72) score += 2;
  }
  if (/hacker news/i.test(link) || /ycombinator/i.test(link) || /hnrss/i.test(link)) score += 1;
  if (/openai|gemini|anthropic|postgres|redis|docker|kubernetes|python|backend|llm|rag/i.test(text)) score += 2;

  const normalizedTitle = title.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
  const dedupeKey = link || normalizedTitle;
  const candidate = {
    title,
    snippet: snippet.slice(0, 500),
    link,
    source,
    isoDate,
    heuristicScore: score,
  };

  const previous = byKey.get(dedupeKey);
  if (!previous || candidate.heuristicScore > previous.heuristicScore || candidate.snippet.length > previous.snippet.length) {
    byKey.set(dedupeKey, candidate);
  }
}

const candidates = [...byKey.values()]
  .sort((a, b) => {
    if (b.heuristicScore !== a.heuristicScore) return b.heuristicScore - a.heuristicScore;
    return String(b.isoDate).localeCompare(String(a.isoDate));
  })
  .slice(0, maxCandidates)
  .map((item, index) => ({
    rank_preliminar: index + 1,
    titulo: item.title,
    descricao: item.snippet,
    link: item.link,
    fonte: item.source,
    publicado_em: item.isoDate,
    score_heuristico: item.heuristicScore,
  }));

if (candidates.length === 0) {
  return [];
}

const selectionPrompt = [
  'Voce e um editor tecnico de newsletter para devs.',
  'Recebera uma lista pre-filtrada de noticias de tecnologia.',
  'Tarefas:',
  '1. Deduplicar temas parecidos.',
  '2. Escolher no maximo 6 noticias.',
  '3. Priorizar relevancia pratica para backend, IA aplicada, dados, arquitetura e tooling.',
  '4. Classificar cada item como aprendizado ou atualizacao.',
  '5. Gerar um resumo curto e objetivo em portugues para cada item.',
  'Use somente os dados recebidos. Nao invente fatos.',
  'Responda estritamente em JSON valido com esta estrutura:',
  '{"selected":[{"titulo":"...","categoria":"aprendizado|atualizacao","resumo":"...","link":"...","fonte":"...","score":1}],"observacao":"..."}',
  '',
  'Noticias:',
  JSON.stringify(candidates),
].join('\n');

return [{
  json: {
    candidateCount: candidates.length,
    candidates,
    selectionPrompt,
  },
}];

const getFallbackCandidates = () => {
  try {
    const previousItems = $items('Prepare Candidate Batch', 0, 0);
    return Array.isArray(previousItems?.[0]?.json?.candidates) ? previousItems[0].json.candidates : [];
  } catch {
    return [];
  }
};

const fallbackCandidates = getFallbackCandidates();
const raw = String(items[0].json.candidates?.[0]?.content?.parts?.[0]?.text || '');
const clean = raw.replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch {
  parsed = { selected: [] };
}

let selected = Array.isArray(parsed.selected) ? parsed.selected : [];
selected = selected
  .filter((item) => item && item.titulo && item.link)
  .slice(0, 6)
  .map((item) => ({
    titulo: String(item.titulo).trim(),
    categoria: String(item.categoria || 'atualizacao').trim().toLowerCase() === 'aprendizado' ? 'aprendizado' : 'atualizacao',
    resumo: String(item.resumo || '').trim().slice(0, 280),
    link: String(item.link).trim(),
    fonte: String(item.fonte || 'RSS').trim(),
    score: Number(item.score) || 5,
  }));

if (selected.length === 0) {
  selected = fallbackCandidates.slice(0, 5).map((item, index) => ({
    titulo: String(item.titulo || item.title || '').trim(),
    categoria: index < 2 ? 'aprendizado' : 'atualizacao',
    resumo: String(item.descricao || item.snippet || '').trim().slice(0, 220),
    link: String(item.link || '').trim(),
    fonte: String(item.fonte || item.source || 'RSS').trim(),
    score: Number(item.score_heuristico) || 5,
  })).filter((item) => item.titulo && item.link);
}

if (selected.length === 0) {
  return [];
}

const digestPrompt = [
  'Voce escreve um resumo diario tecnico para Telegram.',
  'Use tom direto, util e curto.',
  'Nao invente detalhes.',
  'Estruture a resposta em portugues.',
  'Use exatamente o titulo Resumo Diario na primeira linha.',
  'Separe em duas secoes: Aprendizado e Atualizacoes.',
  'Use no maximo 1-2 linhas por noticia.',
  'Em cada noticia, use este bloco na ordem exata: titulo, resumo, linha Link:, URL em linha separada e uma linha em branco extra antes da proxima noticia.',
  'Finalize com uma linha de fechamento curta.',
  'Responda estritamente em JSON valido no formato {"text":"..."}.',
  '',
  'Noticias selecionadas:',
  JSON.stringify(selected),
].join('\n');

return [{
  json: {
    selected,
    selectedCount: selected.length,
    digestPrompt,
  },
}];

const TELEGRAM_MAX_LENGTH = 3900;
const TRUNCATION_SUFFIX = '\n\n<i>...mensagem cortada para caber no Telegram.</i>';

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;');

const decodeHtmlEntities = (value) => String(value || '')
  .replace(/&quot;/g, '"')
  .replace(/&gt;/g, '>')
  .replace(/&lt;/g, '<')
  .replace(/&amp;/g, '&');

const getVisibleLength = (value) => decodeHtmlEntities(String(value || '').replace(/<[^>]+>/g, '')).length;
const getRawLength = (value) => String(value || '').length;
const fitsTelegram = (value, maxLength = TELEGRAM_MAX_LENGTH) => getVisibleLength(value) <= maxLength && getRawLength(value) <= maxLength;

const buildTelegramLink = (url, label = 'Abrir noticia') => {
  const safeUrl = escapeHtml(url);
  const safeLabel = escapeHtml(label);
  return `<a href=\"${safeUrl}\">${safeLabel}</a>`;
};

const linkify = (value) => escapeHtml(value).replace(/(https?:\/\/[^\s<]+)/g, (url) => buildTelegramLink(url, 'link'));

const parseGeminiDigest = () => {
  const raw = String(items[0].json.candidates?.[0]?.content?.parts?.[0]?.text || '');
  const clean = raw.replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();

  if (!clean) {
    return '';
  }

  try {
    const parsed = JSON.parse(clean);
    if (typeof parsed.text === 'string' && parsed.text.trim()) {
      return parsed.text.trim();
    }
  } catch {
    // If Gemini returned plain text instead of JSON, keep the sanitized body below.
  }

  return clean;
};

const getSelected = () => {
  try {
    const previousItems = $items('Parse Selected Stories', 0, 0);
    return Array.isArray(previousItems?.[0]?.json?.selected) ? previousItems[0].json.selected : [];
  } catch {
